INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-10ced7e2-moex-00261', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '德國為內閣制國家，2021年國會大選結果，席次率最高的三個政黨依序為：社民黨約占25.7%，基民盟約 占24.1%，綠黨約占14.8%；最後由社民黨的蕭茲（OlafScholz）擔任總理一職。依據德國的政府體制判 斷，下列分析何者正確？', '["社民黨可主導與其他政黨籌組聯合內閣或執政聯盟", "執政黨所提的法案若未通過，可移請國會進行覆議", "蕭茲擔任國家元首職務，屬不具政治實權的精神領袖", "行政機關不須對立法機關負責，落實分權制衡的原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00262', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '甲選區舉行立法委員罷免案投票，該區選舉人總數為235,024人，依選舉委員會統計，投票率為41.93%， 同意票54,813張、不同意票43,340張。依公職人員選舉罷免法規定，此罷免案通過與否的主要理由為何？', '["罷免案通過，因同意罷免的票數多於不同意罷免的票數", "罷免案通過，因罷免案之投票率達選舉人總數四分之一", "罷免案不通過，因罷免案之投票率未達選舉人總數二分之一", "罷免案不通過，因同意票未達選舉人總數四分之一以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00263', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '關於利益團體與政黨的比較，下列敘述何者正確？', '["利益團體關注的政策面向較政黨更全面", "利益團體及政黨均為人民參政權的展現", "利益團體與政黨皆受人民團體法規範", "利益團體與政黨可透過倡議方式影響政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00264', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '依據公民投票法之規定，下列敘述何者正確？', '["公民投票涉及原住民族權利者，不得違反原住民族基本法之規定", "公民投票僅限於全國性公民投票，地方自治團體不得舉辦地方性公民投票", "立法院基於責任政治之要求，不得提案舉辦公民投票", "經複決廢止之法律，立法機關仍得於1年後再制定相同之法律"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00265', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '依據公職人員選舉罷免法之規定，下列何者具有候選人登記資格？', '["現於區公所服替代役之役男", "私立大學碩士班之在籍學生", "曾犯貪污罪而受緩刑宣告者", "受破產宣告確定而尚未復權者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00266', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '依據臺灣地區與大陸地區人民關係條例之規定，若大陸地區人民未經許可進入臺灣地區，由下列何機關執 行強制出境作業？', '["內政部移民署", "內政部警政署", "行政院大陸委員會", "海洋委員會海巡署"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00267', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '民主國家對於政府應擔負服務人民的角色有不同的期許，下列何者是最基本的民主價值，也是有限政府應 從事的作為？', '["充分保障私有財產權", "有免費疫苗可以施打", "就讀高等教育免學費", "控制物價與通貨膨脹"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00268', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '某國國會眾議院大選剛落幕，現任總理所屬的執政黨「不滿公民行動」痛失第一大黨地位，兩大反對聯盟 「一起」和「海盜和市長」合計席次過半，已宣布合作組閣，產生新的政府。該國應屬於那種政府體制？', '["內閣制", "總統制", "混合制", "委員會制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00269', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '甲借錢給設籍高雄但久居新北市某公寓的乙，乙未依約定即時還款並有持續拖延之傾向，請問甲該如何救 濟其權利？', '["僅得向高雄地方法院提起民事訴訟", "訴訟前應先向調解委員會申請調解", "甲乙於法院審理中得成立和解方案", "甲必須聘請律師方可提出民事訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00270', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '下列四則新聞標題，何者合乎相關法規？', '["被告欲繳罰金，檢察官拒絕易科罰金並發監執行", "酒駕犯獲緩起訴，民眾抨擊法官縱容酒駕", "酒測值誤差獲無罪，公設辯護人為酒駕被害人上訴", "正義波麗士，熱血員警為被害人提出公訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
